#!/usr/bin/env bash
#
# stt-bench.sh — reproducible STT latency benchmark.
#
# Feeds ONE deterministic audio fixture (generated by macOS `say`, so it's
# byte-identical every run) through a transcription endpoint N times and
# reports the per-request timing breakdown + medians. Because the input never
# varies, differences between runs are network/model — exactly what we're
# comparing.
#
# This benchmarks the cloud round-trip in isolation; it does NOT exercise the
# app's in-recording connection pre-warm (that's validated separately via the
# app's own `category == "latency"` os_log on real dictations).
#
# Usage:
#   Scripts/stt-bench.sh [preset] [runs]
#
# Presets (transport × provider):
#   backend               REAL production path: multipart → Sayful Cloud backend  (counts against quota!)
#   backend-reserved      backend path with a pre-created STT reservation       (counts against quota!)
#   openrouter-json       app's BYOK shape: base64 inside JSON → OpenRouter        (default)
#   openrouter-multipart  standard multipart file upload → OpenRouter
#   groq                  multipart → Groq whisper-large-v3-turbo  (needs GROQ_API_KEY)
#   custom                fully manual via env (STT_BASE_URL/STT_MODEL/STT_API_KEY/STT_MODE)
#
# Env overrides (all optional):
#   PHRASE   text spoken into the fixture   (default: canonical ~8s dictation)
#   FIXTURE  path to the wav                 (default: /tmp/sayful-stt-fixture.wav)
#   RUNS     number of requests             (default: 10, or 2nd positional arg)
#   STT_PROMPT optional transcription guidance sent as the provider `prompt`
#   STT_BASE_URL / STT_MODEL / STT_API_KEY / STT_MODE   (for preset=custom)
#
# The OpenRouter key is read from the app's Keychain automatically
# (service com.antonpinkevych.lang-flip / account cloud-ai-api-key); macOS will
# prompt to allow access the first time.

set -euo pipefail

# Auto-load API keys from an env file OUTSIDE any git tree, so a key can never
# be committed. Create ~/.sayful-bench.env with e.g. `GROQ_API_KEY=gsk_...`.
# Existing environment variables win (explicit override still works).
BENCH_ENV="${BENCH_ENV:-$HOME/.sayful-bench.env}"
if [[ -f "$BENCH_ENV" ]]; then
  set -a; # shellcheck disable=SC1090
  source "$BENCH_ENV"; set +a
fi

PRESET="${1:-openrouter-json}"
RUNS="${2:-${RUNS:-10}}"
FIXTURE="${FIXTURE:-/tmp/sayful-stt-fixture.wav}"
PHRASE="${PHRASE:-Hey team, quick update on the project. I finished the latency instrumentation today and the next step is to benchmark the speech to text pipeline.}"
STT_PROMPT="${STT_PROMPT:-}"

keychain_openrouter_key() {
  security find-generic-password -s com.antonpinkevych.lang-flip -a cloud-ai-api-key -w 2>/dev/null || true
}

# Per-preset request shape. Defaults match the OpenAI/OpenRouter transcription
# API; the backend preset overrides path/field/headers for the Sayful proxy.
EP_PATH="audio/transcriptions"   # endpoint path under BASE_URL
FILE_FIELD="file"                # multipart field name for the audio
EXTRA_HEADERS=()                 # extra -H headers (e.g. supabase apikey)
RESERVE_ENDPOINT=""              # for backend-reserved

# ---- Resolve preset → (base url, model, key, transport mode) ----------------
case "$PRESET" in
  backend|backend-reserved)
    SUPA="https://bpxsmfdpmbfsvdckndpw.supabase.co"
    ANON="eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImJweHNtZmRwbWJmc3ZkY2tuZHB3Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3ODIzMDI5NDAsImV4cCI6MjA5Nzg3ODk0MH0.FzxlUqw7iH0PhmSVrHKOfd6MMhoEL_tyhaSqXf6-VHY"
    BASE_URL="$SUPA/functions/v1"; EP_PATH="transcribe"; FILE_FIELD="audio"
    MODEL="${STT_MODEL:-}"; MODE="multipart"
    EXTRA_HEADERS=(-H "apikey: $ANON")
    if [[ "$PRESET" == "backend-reserved" ]]; then
      RESERVE_ENDPOINT="$SUPA/functions/v1/stt-reserve"
    fi
    API_KEY="${STT_API_KEY:-$(security find-generic-password -s com.antonpinkevych.lang-flip -a backend-access-token -w 2>/dev/null || true)}" ;;
  openrouter-json)
    BASE_URL="https://openrouter.ai/api/v1"; MODEL="openai/whisper-large-v3"; MODE="json"
    API_KEY="${STT_API_KEY:-$(keychain_openrouter_key)}" ;;
  openrouter-multipart)
    BASE_URL="https://openrouter.ai/api/v1"; MODEL="openai/whisper-large-v3"; MODE="multipart"
    API_KEY="${STT_API_KEY:-$(keychain_openrouter_key)}" ;;
  groq)
    BASE_URL="https://api.groq.com/openai/v1"; MODEL="${STT_MODEL:-whisper-large-v3-turbo}"; MODE="multipart"
    API_KEY="${STT_API_KEY:-${GROQ_API_KEY:-}}" ;;
  custom)
    BASE_URL="${STT_BASE_URL:?set STT_BASE_URL}"; MODEL="${STT_MODEL:?set STT_MODEL}"
    MODE="${STT_MODE:-multipart}"; API_KEY="${STT_API_KEY:?set STT_API_KEY}" ;;
  *) echo "unknown preset: $PRESET" >&2; exit 2 ;;
esac

if [[ -z "${API_KEY:-}" ]]; then
  echo "✗ no API key for preset '$PRESET' (set STT_API_KEY / GROQ_API_KEY, or allow Keychain access)" >&2
  exit 1
fi

AUTH_CONFIG="$(mktemp)"; chmod 600 "$AUTH_CONFIG"
printf 'header = "Authorization: Bearer %s"\n' "$API_KEY" > "$AUTH_CONFIG"

# ---- Generate the deterministic fixture once --------------------------------
# VOICE picks the `say` voice — e.g. Lesya (uk_UA) / Milena (ru_RU) for Cyrillic
# fixtures, so we can compare STT models on the user's actual languages.
if [[ ! -f "$FIXTURE" ]]; then
  echo "→ generating fixture (16kHz mono Int16 wav, same format the app records)…"
  VOICE_ARG=(); if [[ -n "${VOICE:-}" ]]; then VOICE_ARG=(-v "$VOICE"); fi
  say ${VOICE_ARG[@]+"${VOICE_ARG[@]}"} -o "$FIXTURE" --file-format=WAVE --data-format=LEI16@16000 "$PHRASE"
fi
AUDIO_BYTES=$(stat -f%z "$FIXTURE")
DURATION=$(afinfo "$FIXTURE" 2>/dev/null | awk -F': ' '/estimated duration/{printf "%.1f", $2}')

echo "════════════════════════════════════════════════════════════════"
echo " STT bench · preset=$PRESET · runs=$RUNS"
echo " endpoint=$BASE_URL/$EP_PATH"
echo " model=$MODEL · transport=$MODE"
echo " fixture=${AUDIO_BYTES}B · ~${DURATION}s"
echo "════════════════════════════════════════════════════════════════"

ENDPOINT="$BASE_URL/$EP_PATH"
BODY="$(mktemp)"; PAYLOAD="$(mktemp)"
trap 'rm -f "$BODY" "$PAYLOAD" "$AUTH_CONFIG"' EXIT

# Pre-build the JSON payload (base64 audio) once for json mode.
if [[ "$MODE" == "json" ]]; then
  B64=$(base64 -i "$FIXTURE" | tr -d '\n')
  if [[ -n "$STT_PROMPT" ]]; then
    jq -n --arg model "$MODEL" --arg data "$B64" --arg prompt "$STT_PROMPT" \
      '{model:$model,prompt:$prompt,input_audio:{data:$data,format:"wav"}}' > "$PAYLOAD"
  else
    jq -n --arg model "$MODEL" --arg data "$B64" \
      '{model:$model,input_audio:{data:$data,format:"wav"}}' > "$PAYLOAD"
  fi
fi

# Trailing \n matters: `read` returns non-zero at EOF with no newline, which
# would trip `set -e` even though the vars are populated.
WFMT='%{time_namelookup} %{time_connect} %{time_appconnect} %{time_pretransfer} %{time_starttransfer} %{time_total} %{size_upload} %{http_code}\n'

totals=(); ttfbs=(); transcript=""
printf "\n %-4s %7s %7s %7s %8s %9s %7s %5s\n" "run" "dns" "tcp" "tls" "ttfb" "total" "up(KB)" "code"
printf " %s\n" "────────────────────────────────────────────────────────────"

for i in $(seq 1 "$RUNS"); do
  RESERVE_HEADER=()
  if [[ -n "$RESERVE_ENDPOINT" ]]; then
    RESERVE_BODY="$(mktemp)"
    if [[ -n "$MODEL" ]]; then
      printf '{"model":"%s"}' "$MODEL" > "$RESERVE_BODY"
    else
      printf '{}' > "$RESERVE_BODY"
    fi
    RID=$(curl -s --config "$AUTH_CONFIG" -X POST "$RESERVE_ENDPOINT" \
      ${EXTRA_HEADERS[@]+"${EXTRA_HEADERS[@]}"} \
      -H "Content-Type: application/json" \
      --data @"$RESERVE_BODY" | jq -r '.reservation.id // empty')
    rm -f "$RESERVE_BODY"
    if [[ -n "$RID" ]]; then
      RESERVE_HEADER=(-H "X-Stt-Reservation: $RID")
    fi
  fi

  # Only send `model` when one is set (backend default = empty → server picks).
  MODEL_FIELD=()
  if [[ -n "$MODEL" ]]; then MODEL_FIELD=(-F "model=$MODEL"); fi
  PROMPT_FIELD=()
  if [[ -n "$STT_PROMPT" ]]; then PROMPT_FIELD=(-F "prompt=$STT_PROMPT"); fi
  # bash 3.2 + `set -u`: guard empty-array expansion with the [@]+ idiom.
  if [[ "$MODE" == "json" ]]; then
    read -r dns conn appc pre start total up code < <(curl -s -o "$BODY" -w "$WFMT" \
      --config "$AUTH_CONFIG" \
      -X POST "$ENDPOINT" \
      -H "Content-Type: application/json" \
      ${EXTRA_HEADERS[@]+"${EXTRA_HEADERS[@]}"} \
      ${RESERVE_HEADER[@]+"${RESERVE_HEADER[@]}"} \
      -H "X-Title: Sayful" -H "HTTP-Referer: https://github.com/MikeKorotych/lang-flip" \
      --data @"$PAYLOAD")
  else
    read -r dns conn appc pre start total up code < <(curl -s -o "$BODY" -w "$WFMT" \
      --config "$AUTH_CONFIG" \
      -X POST "$ENDPOINT" \
      ${EXTRA_HEADERS[@]+"${EXTRA_HEADERS[@]}"} \
      ${RESERVE_HEADER[@]+"${RESERVE_HEADER[@]}"} \
      -H "X-Title: Sayful" -H "HTTP-Referer: https://github.com/MikeKorotych/lang-flip" \
      -F "$FILE_FIELD=@$FIXTURE" \
      ${MODEL_FIELD[@]+"${MODEL_FIELD[@]}"} \
      ${PROMPT_FIELD[@]+"${PROMPT_FIELD[@]}"})
  fi

  # cumulative seconds → per-phase milliseconds
  read -r d t s f tot < <(awk -v dns="$dns" -v conn="$conn" -v appc="$appc" -v pre="$pre" -v start="$start" -v total="$total" \
    'BEGIN{printf "%.0f %.0f %.0f %.0f %.0f\n", dns*1000, (conn-dns)*1000, (appc>0?(appc-conn)*1000:0), (start-pre)*1000, total*1000}')
  upkb=$(awk -v u="$up" 'BEGIN{printf "%.0f", u/1024}')
  printf " %-4s %7s %7s %7s %8s %9s %7s %5s\n" "$i" "$d" "$t" "$s" "$f" "$tot" "$upkb" "$code"

  totals+=("$tot"); ttfbs+=("$f")
  if [[ "$code" == "200" && -z "$transcript" ]]; then
    transcript=$(jq -r '.text // empty' "$BODY" 2>/dev/null || true)
  fi
done

median() { printf '%s\n' "$@" | sort -n | awk '{a[NR]=$1} END{print (NR%2)? a[(NR+1)/2] : int((a[NR/2]+a[NR/2+1])/2)}'; }

echo
echo " median ttfb  = $(median "${ttfbs[@]}") ms"
echo " median total = $(median "${totals[@]}") ms"
[[ -n "$transcript" ]] && echo " transcript   = \"$transcript\""
echo
